parts.text:
[
  {
    "prototype_name": "Castle Clashers Playable Ad",
    "implementation_summary": "A portrait-oriented 2D tower defense playable ad where the player drags and drops weapons into slots on their blue castle to auto-fire projectiles at the enemy red castle. The first castle to reach 0 health loses. Built as a single HTML file using Canvas API, with base64 encoded assets.",
    "screen": {
      "orientation": "portrait",
      "logical_width": 720,
      "logical_height": 1280,
      "responsive_strategy": "Scale canvas to fit window while maintaining aspect ratio, centering it vertically and horizontally. Background image will be centered and cropped to fill the screen."
    },
    "gameplay": {
      "objective": "Destroy the enemy red castle before the player's blue castle is destroyed.",
      "primary_interaction": "Drag and drop weapon icons from the bottom UI into empty slots on the player's castle.",
      "win_condition": "Enemy castle health reaches 0.",
      "loss_or_timeout_condition": "Player castle health reaches 0 or 30 seconds elapse.",
      "session_length_seconds": 30
    },
    "entities": [
      {
        "id": "player_castle",
        "role": "Player Base",
        "asset": "Blue Castle.png",
        "behavior": "Static on the bottom-left/center. Has 3 empty slots for weapons. Takes damage from enemy projectiles.",
        "priority": "must"
      },
      {
        "id": "enemy_castle",
        "role": "Enemy Base",
        "asset": "Red Castle.png",
        "behavior": "Static on the top-right/center. Auto-fires projectiles at the player castle at a fixed interval. Takes damage from player projectiles.",
        "priority": "must"
      },
      {
        "id": "deployable_weapon_1",
        "role": "Player Unit",
        "asset": "Weapon_1.png",
        "behavior": "Draggable from bottom UI. Once placed in a slot, auto-fires Projectile_1 at the enemy castle.",
        "priority": "must"
      },
      {
        "id": "deployable_weapon_2",
        "role": "Player Unit",
        "asset": "Weapon_2.png",
        "behavior": "Draggable from bottom UI. Once placed in a slot, auto-fires Projectile_1 at the enemy castle with different stats.",
        "priority": "should"
      },
      {
        "id": "player_projectile",
        "role": "Damage Source",
        "asset": "Projectile_1.png",
        "behavior": "Moves linearly from player weapon slot to enemy castle. On impact, reduces enemy health and triggers explosion particles.",
        "priority": "must"
      },
      {
        "id": "enemy_projectile",
        "role": "Damage Source",
        "asset": "Projectile_2.png",
        "behavior": "Moves linearly from enemy castle to player castle. On impact, reduces player health and triggers explosion particles.",
        "priority": "must"
      },
      {
        "id": "background",
        "role": "Environment",
        "asset": "Background.png",
        "behavior": "Static background, scaled to cover the canvas.",
        "priority": "must"
      }
    ],
    "asset_plan": [
      {
        "asset_path": "Background.png",
        "use": "Environment background",
        "processing": "Base64 encode. Scale and crop to fit 720x1280.",
        "required": true
      },
      {
        "asset_path": "Blue Castle.png",
        "use": "Player base visual",
        "processing": "Base64 encode. Scale down to fit bottom half of screen.",
        "required": true
      },
      {
        "asset_path": "Red Castle.png",
        "use": "Enemy base visual",
        "processing": "Base64 encode. Scale down to fit top half of screen.",
        "required": true
      },
      {
        "asset_path": "Weapon_1.png",
        "use": "Deployable unit icon and placed unit visual",
        "processing": "Base64 encode. Used instead of .psb character files for native HTML5 compatibility.",
        "required": true
      },
      {
        "asset_path": "Weapon_2.png",
        "use": "Alternative deployable unit",
        "processing": "Base64 encode.",
        "required": false
      },
      {
        "asset_path": "Projectile_1.png",
        "use": "Player projectile visual",
        "processing": "Base64 encode. Scale down appropriately.",
        "required": true
      },
      {
        "asset_path": "Projectile_2.png",
        "use": "Enemy projectile visual",
        "processing": "Base64 encode. Scale down appropriately.",
        "required": true
      },
      {
        "asset_path": "Music.ogg",
        "use": "Background music",
        "processing": "Base64 encode as data URI. Autoplay on first interaction.",
        "required": false
      },
      {
        "asset_path": "Sfx.wav",
        "use": "Projectile impact sound",
        "processing": "Base64 encode as data URI. Play on collision.",
        "required": false
      }
    ],
    "interaction_flow": [
      {
        "step": 1,
        "player_action": "None (Idle)",
        "system_response": "Enemy castle begins firing projectiles at the player castle, depleting its health bar to create urgency."
      },
      {
        "step": 2,
        "player_action": "Touch and drag Weapon_1 from the bottom UI panel",
        "system_response": "Weapon icon follows the pointer. Castle slots are highlighted."
      },
      {
        "step": 3,
        "player_action": "Release touch over an empty slot on the Blue Castle",
        "system_response": "Weapon snaps to the slot and immediately begins auto-firing Projectile_1 at the Red Castle."
      },
      {
        "step": 4,
        "player_action": "Wait and watch",
        "system_response": "Projectiles exchange. Health bars deplete. Damage numbers pop up on impacts."
      },
      {
        "step": 5,
        "player_action": "None (Game Over)",
        "system_response": "When a health bar reaches 0, the destroyed castle shakes and fades. A 'Download Now' CTA overlay appears."
      }
    ],
    "parameters": [
      {
        "name": "enemy_fire_rate_ms",
        "type": "number",
        "default": 1500,
        "variation_range": "800 - 2500",
        "gameplay_effect": "Determines how fast the enemy attacks, directly impacting difficulty and urgency."
      },
      {
        "name": "player_fire_rate_ms",
        "type": "number",
        "default": 1000,
        "variation_range": "500 - 2000",
        "gameplay_effect": "Determines how fast placed player weapons attack."
      },
      {
        "name": "castle_max_health",
        "type": "number",
        "default": 100,
        "variation_range": "50 - 300",
        "gameplay_effect": "Scales the duration of the playable ad."
      },
      {
        "name": "projectile_damage",
        "type": "number",
        "default": 10,
        "variation_range": "5 - 25",
        "gameplay_effect": "Changes how many hits are required to destroy a castle."
      }
    ],
    "acceptance_criteria": [
      "Game is contained entirely within a single HTML file under 5MB.",
      "No external network requests are made for assets or libraries.",
      "Player can successfully drag a weapon from the UI and drop it into a castle slot.",
      "Placed weapons automatically fire projectiles at the enemy.",
      "Enemy castle automatically fires projectiles at the player.",
      "Health bars accurately reflect damage taken from projectile collisions.",
      "A clear Win or Loss state is presented when a castle's health reaches 0."
    ],
    "non_goals_v1": [
      "Parsing or rendering .psb (Photoshop Big) files; standard PNG weapons will be used as deployables instead.",
      "Complex physics-based destruction of the castles (simple screen shake and particle bursts will be used).",
      "Resource management (e.g., gold or mana costs for deploying units).",
      "Moving castles (castles will remain static to simplify the 2D canvas logic)."
    ]
  }
]
